/* AUTO-GENERATED I18N EXTENSIONS END */

(function() {
  const STORAGE_KEY = 'mlc-lang';
  const SUPPORTED_LANGS = ['en', 'es', 'fr'];
  const originalTextNodes = new WeakMap();
  const originalAttrs = new WeakMap();
  let originalsCaptured = false;

  function getLang() {
    const saved = localStorage.getItem(STORAGE_KEY) || 'en';
    return SUPPORTED_LANGS.includes(saved) ? saved : 'en';
  }

  function setLang(lang) {
    if (!SUPPORTED_LANGS.includes(lang)) lang = 'en';
    localStorage.setItem(STORAGE_KEY, lang);
    applyLang(lang);
  }

  function normalizeText(value) {
    return String(value || '').replace(/\s+/g, ' ').trim();
  }

  function hasLetters(value) {
    return /[A-Za-zÀ-ÖØ-öø-ÿ]/.test(value);
  }

  function preserveWhitespace(original, translated) {
    const lead = original.match(/^\s*/)?.[0] || '';
    const tail = original.match(/\s*$/)?.[0] || '';
    return `${lead}${translated}${tail}`;
  }

  function shouldSkipTextNode(node) {
    const parent = node.parentElement;
    if (!parent) return true;
    return Boolean(parent.closest('script, style, noscript, template, svg, canvas, [data-i18n], .lang-toggle, .nav-toggle'));
  }

  function captureOriginals() {
    if (originalsCaptured) return;
    const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, {
      acceptNode(node) {
        const key = normalizeText(node.nodeValue);
        if (!key || !hasLetters(key) || shouldSkipTextNode(node)) return NodeFilter.FILTER_REJECT;
        return NodeFilter.FILTER_ACCEPT;
      }
    });

    while (walker.nextNode()) {
      originalTextNodes.set(walker.currentNode, walker.currentNode.nodeValue);
    }

    const attrNames = ['title', 'aria-label', 'alt', 'placeholder', 'value', 'content'];
    document.querySelectorAll('[title], [aria-label], img[alt], input[placeholder], textarea[placeholder], input[value], meta[name="description"], meta[property^="og:"]').forEach(el => {
      if (el.closest?.('[data-i18n-placeholder], [data-i18n-value], .lang-toggle, .nav-toggle')) return;
      const attrs = {};
      attrNames.forEach(name => {
        if (!el.hasAttribute(name)) return;
        const value = el.getAttribute(name);
        if (normalizeText(value) && hasLetters(value)) attrs[name] = value;
      });
      if (Object.keys(attrs).length) originalAttrs.set(el, attrs);
    });

    if (document.title) {
      originalAttrs.set(document, { title: document.title });
    }

    originalsCaptured = true;
  }

  function translateStaticText(lang) {
    const dict = pageTextTranslations[lang] || {};

    originalTextNodes.forEach?.(() => {});
    const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, {
      acceptNode(node) {
        if (!originalTextNodes.has(node)) return NodeFilter.FILTER_REJECT;
        if (shouldSkipTextNode(node)) return NodeFilter.FILTER_REJECT;
        return NodeFilter.FILTER_ACCEPT;
      }
    });

    while (walker.nextNode()) {
      const node = walker.currentNode;
      const original = originalTextNodes.get(node);
      const key = normalizeText(original);
      if (lang === 'en') {
        node.nodeValue = original;
      } else if (dict[key]) {
        node.nodeValue = preserveWhitespace(original, dict[key]);
      }
    }

    originalAttrs.forEach?.(() => {});
    document.querySelectorAll('[title], [aria-label], img[alt], input[placeholder], textarea[placeholder], input[value], meta[name="description"], meta[property^="og:"]').forEach(el => {
      const attrs = originalAttrs.get(el);
      if (!attrs) return;
      Object.entries(attrs).forEach(([name, original]) => {
        const key = normalizeText(original);
        const value = lang === 'en' ? original : (dict[key] || original);
        el.setAttribute(name, value);
      });
    });

    const docAttrs = originalAttrs.get(document);
    if (docAttrs?.title) {
      const key = normalizeText(docAttrs.title);
      document.title = lang === 'en' ? docAttrs.title : (dict[key] || docAttrs.title);
    }
  }

  function ensureToggle() {
    if (!document.getElementById('mlc-i18n-toggle-style')) {
      const style = document.createElement('style');
      style.id = 'mlc-i18n-toggle-style';
      style.textContent = `
        .lang-toggle .lang-active{font-family:Inter,system-ui,sans-serif;font-size:12px;font-weight:700;color:#fff;letter-spacing:.04em}
        .lang-toggle .lang-inactive{font-family:Inter,system-ui,sans-serif;font-size:12px;font-weight:500;color:rgba(255,255,255,.45);letter-spacing:.04em}
        .lang-toggle .lang-divider{font-family:Inter,system-ui,sans-serif;font-size:12px;color:rgba(255,255,255,.28);margin:0 1px}
      `;
      document.head.appendChild(style);
    }

    let toggle = document.getElementById('langToggle');
    if (toggle) return toggle;

    toggle = document.createElement('button');
    toggle.id = 'langToggle';
    toggle.className = 'lang-toggle';
    toggle.type = 'button';
    toggle.setAttribute('aria-label', 'Toggle language');
    toggle.style.cssText = [
      'position:fixed',
      'top:18px',
      'right:18px',
      'z-index:10000',
      'display:flex',
      'align-items:center',
      'gap:2px',
      'background:rgba(10,10,15,0.82)',
      'border:1px solid rgba(255,255,255,0.18)',
      'border-radius:999px',
      'padding:7px 13px',
      'cursor:pointer',
      'backdrop-filter:blur(18px)',
      '-webkit-backdrop-filter:blur(18px)'
    ].join(';');
    document.body.appendChild(toggle);
    return toggle;
  }

  function renderToggle(lang) {
    const toggle = ensureToggle();
    toggle.innerHTML = SUPPORTED_LANGS.map((code, index) => {
      const label = code.toUpperCase();
      const className = code === lang ? 'lang-active' : 'lang-inactive';
      const divider = index < SUPPORTED_LANGS.length - 1 ? '<span class="lang-divider">/</span>' : '';
      return `<span class="${className}">${label}</span>${divider}`;
    }).join('');
  }

  function applyLang(lang) {
    const dict = translations[lang];
    if (!dict) lang = 'en';
    const activeDict = translations[lang] || translations.en;

    captureOriginals();

    document.documentElement.lang = lang;

    document.querySelectorAll('[data-i18n]').forEach(el => {
      const key = el.dataset.i18n;
      const value = activeDict[key] ?? translations.en[key];
      if (value === undefined) return;

      // For elements that contain HTML (spans, br tags, etc.)
      if (value.includes('<')) {
        el.innerHTML = value;
      } else {
        el.textContent = value;
      }
    });

    document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
      const key = el.dataset.i18nPlaceholder;
      const value = activeDict[key] ?? translations.en[key];
      if (value !== undefined) el.setAttribute('placeholder', value);
    });

    document.querySelectorAll('[data-i18n-value]').forEach(el => {
      const key = el.dataset.i18nValue;
      const value = activeDict[key] ?? translations.en[key];
      if (value !== undefined) el.setAttribute('value', value);
    });

    translateStaticText(lang);

    // Update toggle button labels
    renderToggle(lang);
  }

  // Init on DOM ready
  document.addEventListener('DOMContentLoaded', () => {
    const lang = getLang();
    applyLang(lang);

    const toggle = ensureToggle();
    if (toggle) {
      toggle.addEventListener('click', () => {
        const current = getLang();
        const next = SUPPORTED_LANGS[(SUPPORTED_LANGS.indexOf(current) + 1) % SUPPORTED_LANGS.length];
        setLang(next);
      });
    }
  });
})();
